CREATE TYPE "AutomationStatus" AS ENUM ('DRAFT','PUBLISHED','PAUSED','ARCHIVED');
CREATE TYPE "AutomationTriggerType" AS ENUM ('DOMAIN_EVENT','SCHEDULE','MANUAL','WEBHOOK','SLA_BREACH','APPROVAL_DECISION','RULE_MATCH');
CREATE TYPE "AutomationExecutionStatus" AS ENUM ('RUNNING','SUCCEEDED','FAILED','SKIPPED','DRY_RUN');
CREATE TABLE "AutomationDefinition" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" "AutomationStatus" NOT NULL DEFAULT 'DRAFT',"activeVersionId" TEXT,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AutomationVersion" ("id" TEXT PRIMARY KEY,"definitionId" TEXT NOT NULL,"version" INTEGER NOT NULL,"triggerType" "AutomationTriggerType" NOT NULL,"triggerConfig" JSONB NOT NULL DEFAULT '{}',"conditions" JSONB,"actions" JSONB NOT NULL,"publishedAt" TIMESTAMP(3),"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AutomationExecution" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"definitionId" TEXT NOT NULL,"versionId" TEXT NOT NULL,"status" "AutomationExecutionStatus" NOT NULL,"triggerType" "AutomationTriggerType" NOT NULL,"triggerPayload" JSONB NOT NULL DEFAULT '{}',"context" JSONB NOT NULL DEFAULT '{}',"actionResults" JSONB NOT NULL DEFAULT '[]',"error" TEXT,"dryRun" BOOLEAN NOT NULL DEFAULT false,"startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"completedAt" TIMESTAMP(3),"initiatedById" TEXT);
CREATE UNIQUE INDEX "AutomationDefinition_organizationId_key_key" ON "AutomationDefinition"("organizationId","key"); CREATE INDEX "AutomationDefinition_organizationId_status_idx" ON "AutomationDefinition"("organizationId","status"); CREATE UNIQUE INDEX "AutomationVersion_definitionId_version_key" ON "AutomationVersion"("definitionId","version"); CREATE INDEX "AutomationExecution_organizationId_status_startedAt_idx" ON "AutomationExecution"("organizationId","status","startedAt");
ALTER TABLE "AutomationDefinition" ADD CONSTRAINT "AutomationDefinition_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE; ALTER TABLE "AutomationVersion" ADD CONSTRAINT "AutomationVersion_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "AutomationDefinition"("id") ON DELETE CASCADE; ALTER TABLE "AutomationExecution" ADD CONSTRAINT "AutomationExecution_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE; ALTER TABLE "AutomationExecution" ADD CONSTRAINT "AutomationExecution_definitionId_fkey" FOREIGN KEY ("definitionId") REFERENCES "AutomationDefinition"("id") ON DELETE CASCADE; ALTER TABLE "AutomationExecution" ADD CONSTRAINT "AutomationExecution_versionId_fkey" FOREIGN KEY ("versionId") REFERENCES "AutomationVersion"("id") ON DELETE RESTRICT;
